#include <stdio.h>
#include <fcntl.h>
#include <sys/mman.h>
#include <sys/stat.h>
#include <sys/wait.h>
#include <unistd.h>

int main(void) {
    int fd = shm_open("/kf_shm_rw", O_CREAT | O_RDWR, 0644);
    ftruncate(fd, 4096);
    int *shared = (int *)mmap(NULL, 4096, PROT_READ | PROT_WRITE, MAP_SHARED, fd, 0);
    close(fd);

    *shared = 0;
    pid_t pid = fork();
    if (pid == 0) {
        *shared = 99;
        _exit(0);
    }
    wait(NULL);
    printf("Parent reads: %d\n", *shared);

    munmap(shared, 4096);
    shm_unlink("/kf_shm_rw");
    return 0;
}

